@Service
class NotificationService {
    @GrpcClient("notification-grpc")
    private lateinit var notificationStub: NotificationServiceGrpc.NotificationServiceBlockingStub

    fun getNotifications(userId: String, limit: Int, offset: Int): GetNotificationsResponse {
        val request = GetNotificationsRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .build()
        return try {
            notificationStub.getNotifications(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException("NOTIFICATION_ERROR", e.status.description)
        }
    }
